root.1/terminology_glossary:
{
  "Payment": {
    "en": "Payment",
    "kr": "결제",
    "context": "The core transaction entity representing a monetary transfer."
  },
  "Transaction": {
    "en": "Transaction",
    "kr": "거래",
    "context": "A broader record of financial activity, including refunds and captures."
  },
  "Merchant": {
    "en": "Merchant",
    "kr": "가맹점",
    "context": "The entity accepting payments."
  },
  "Customer": {
    "en": "Customer",
    "kr": "고객",
    "context": "The entity initiating the payment."
  },
  "Refund": {
    "en": "Refund",
    "kr": "환불",
    "context": "Returning funds to the customer."
  },
  "Capture": {
    "en": "Capture",
    "kr": "청구",
    "context": "Finalizing an authorized payment."
  },
  "Authorization": {
    "en": "Authorization",
    "kr": "승인",
    "context": "Reserving funds before capture."
  },
  "Webhook": {
    "en": "Webhook",
    "kr": "웹훅",
    "context": "Event notification endpoint."
  },
  "Error": {
    "en": "Error",
    "kr": "오류",
    "context": "General failure state."
  },
  "Success": {
    "en": "Success",
    "kr": "성공",
    "context": "Successful operation state."
  }
}

root.1/naming_conventions:
{
  "endpoint_nouns": {
    "rule": "Use plural, lowercase nouns for resource collections. Use singular nouns for specific actions if not a collection."
  },
  "error_code_structure": {
    "rule": "Format: {CATEGORY}_{SPECIFIC_CODE}. Categories: AUTH, PAYMENT, VALIDATION, SYSTEM. Codes are uppercase snake_case."
  },
  "casing_standards": {
    "json_keys": "snake_case",
    "http_headers": "X-Custom-Header (Title-Case with hyphens)",
    "url_paths": "kebab-case",
    "query_params": "snake_case"
  },
  "versioning": {
    "rule": "Include API version in URL path: /v1/{resource}"
  }
}
